// src/event/Event.js
import React, { useState, useEffect } from 'react';
import './Event.css'; // スタイルシートのインポート

const Event = () => {
  const [events, setEvents] = useState([]);
  const [newEvent, setNewEvent] = useState({ event_name: '', event_state: 'draft', event_info: '' });
  const [selectedEventId, setSelectedEventId] = useState(null); // 選択されたイベントIDの状態
  const [selectedEvent, setSelectedEvent] = useState(null); // 選択されたイベントの詳細情報を取得するための状態

  // イベントリストを取得する
  const fetchEvents = async () => {
    const response = await fetch('http://localhost:8000/event/get');
    const data = await response.json();
    setEvents(data);
  };

  // 選択されたイベントIDが変更されたときに、そのイベントの詳細情報を取得する
  useEffect(() => {
    const fetchSelectedEvent = async () => {
      if (selectedEventId) {
        const response = await fetch(`http://localhost:8000/event/get/${selectedEventId}`);
        const data = await response.json();
        setSelectedEvent(data);
      }
    };

    fetchSelectedEvent();
  }, [selectedEventId]); // selectedEventIdが変更されたときに実行

  // コンポーネントのマウント時にイベントリストを取得
  useEffect(() => {
    fetchEvents();
  }, []);

  // 新しいイベントを登録する
  const registerEvent = async (e) => {
    e.preventDefault();
    await fetch('http://localhost:8000/event/register', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(newEvent)
    });
    setNewEvent({ event_name: '', event_state: 'draft', event_info: '' });
    fetchEvents(); // リストを更新
  };

  // イベントを更新する
  const updateEvent = async (eventToUpdate) => {
    await fetch(`http://localhost:8000/event/edit/${eventToUpdate.event_id}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(eventToUpdate)
    });
    fetchEvents(); // リストを更新
  };

  // イベントを削除する
  const deleteEvent = async (eventId) => {
    await fetch(`http://localhost:8000/event/delete/${eventId}`, { method: 'DELETE' });
    fetchEvents(); // リストを更新
  };

  // イベント名をクリックしたときの処理
  const handleEventSelect = async (eventId) => {
    setSelectedEventId(eventId);
    const response = await fetch(`http://localhost:8000/event/get/${eventId}`);
    const data = await response.json();
    setSelectedEvent(data);
  };

  return (
    <div className="event-container">
      <div className="event-registration">
        <h2>イベント登録</h2>
        <form onSubmit={registerEvent}>
          <label>
           bytes: \xe3\x82bytes:\xa4bytes:\xe3\x83bytes:\x99ント名:
            <input
              type="text"
              value={newEvent.event_name}
              onChange={(e) => setNewEvent({ ...newEvent, event_name: e.target.value })}
              placeholder="イbytes:\xe3\x83bytes:\x99ント名"
              required
            />
          </label>
          <label>
           bytes: \xe3\x82bytes:\xa4bytes:\xe3\x83bytes:\x99ント内容:
            <input
              type="text"
              value={newEvent.event_info}
              onChange={(e) => setNewEvent({ ...newEvent, event_info: e.target.value })}
              placeholder="イベント内容"
              required
            />
          </label>
          <button type="submit">登録</button>
        </form>
      </div>
      <div className="event-list">
        <h2>イベント一覧</h2>
        {events.map((event) => (
          <div key={event.event_id} onClick={() => handleEventSelect(event.event_id)}>
            {event.event_name}
          </div>
        ))}
      </div>
      {selectedEvent && (
        <div className="event-edit">
          <h2>イベント編集</h2>
          <form onSubmit={(e) => {
            e.preventDefault();
            updateEvent(selectedEvent); // 更新処理を呼び出す
          }}>
            <label>
              イベント名:
              <input
                type="text"
                value={selectedEvent.event_name}
                onChange={(e) => setSelectedEvent({ ...selectedEvent, event_name: e.target.value })}
              />
            </label>
            <label>
              イベント内容:
              <input
                type="text"
                value={selectedEvent.event_info}
                onChange={(e) => setSelectedEvent({ ...selectedEvent, event_info: e.target.value })}
              />
            </label>
            <button type="submit">更新</button>
          </form>
        </div>
      )}
    </div>
  );
};

export default Event;
